52	struct common_chat_template {
53	    jinja::program prog;
54	    std::string bos_tok;
55	    std::string eos_tok;
56	    std::string src;
57	    chat_template_caps caps;
58	
59	    common_chat_template(const std::string & src, const std::string & bos_token, const std::string & eos_token) {
60	        jinja::lexer lexer;
61	        auto lexer_res = lexer.tokenize(src);
62	        this->prog = jinja::parse_from_tokens(lexer_res);
63	
64	        this->src = lexer_res.source;
65	        this->bos_tok = bos_token;
66	        this->eos_tok = eos_token;
67	
68	        this->caps = jinja::caps_get(prog);
69	        // LOG_INF("%s: caps:\n%s\n", __func__, this->caps.to_string().c_str());
70	    }
71	
72	    const std::string & source() const { return src; }
73	    const std::string & bos_token() const { return bos_tok; }
74	    const std::string & eos_token() const { return eos_tok; }
75	
76	    chat_template_caps original_caps() const {
77	        return caps;
78	    }
79	};
