211	    } else if (tmpl_contains("<|header_start|>") && tmpl_contains("<|header_end|>")) {
212	        return LLM_CHAT_TEMPLATE_LLAMA4;
213	    } else if (tmpl_contains("<|endofuserprompt|>")) {
214	        return LLM_CHAT_TEMPLATE_DOTS1;
215	    } else if (tmpl_contains("<|extra_0|>") && tmpl_contains("<|extra_4|>")) {
216	        return LLM_CHAT_TEMPLATE_HUNYUAN_MOE;
217	    } else if (tmpl_contains("<|start|>") && tmpl_contains("<|channel|>")) {
218	        return LLM_CHAT_TEMPLATE_OPENAI_MOE;
