953	static void test_peg_parser(common_chat_templates *                      tmpls,
954	                            const std::function<void(peg_test_case &)> & init,
955	                            bool                                         detailed_debug) {
956	    // UTF-8-safe truncation helper (same as in test_parser_with_streaming)
957	    constexpr auto utf8_truncate_safe_len = [](const std::string_view s) -> size_t {
958	        auto len = s.size();
959	        if (len == 0) {
960	            return 0;
961	        }
962	        auto i = len;
963	        for (size_t back = 0; back < 4 && i > 0; ++back) {
964	            --i;
965	            unsigned char c = s[i];
966	            if ((c & 0x80) == 0) {
967	                return len;
968	            }
969	            if ((c & 0xC0) == 0xC0) {
970	                size_t expected_len = 0;
971	                if ((c & 0xE0) == 0xC0) {
972	                    expected_len = 2;
973	                } else if ((c & 0xF0) == 0xE0) {
974	                    expected_len = 3;
975	                } else if ((c & 0xF8) == 0xF0) {
976	                    expected_len = 4;
977	                } else {
978	                    return i;
979	                }
980	                if (len - i >= expected_len) {
981	                    return len;
982	                }
983	                return i;
984	            }
985	        }
986	        return len - std::min(len, size_t(3));
987	    };
